import { TextClassContext } from '@/registry/components/ui/text';
import { cn } from '@/registry/lib/utils';
import { cva, type VariantProps } from 'class-variance-authority';
import { Platform, Pressable } from 'react-native';
import * as React from 'react';

const buttonVariants = cva(
    cn(
        'group shrink-0 flex-row items-center justify-center gap-2 rounded-md shadow-none',
        Platform.select({
            web: "focus-visible:border-ring focus-visible:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive whitespace-nowrap outline-none transition-all focus-visible:ring-[3px] disabled:pointer-events-none [&_svg:not([class*='size-'])]:size-4 [&_svg]:pointer-events-none [&_svg]:shrink-0",
        })
    ),
    {
        variants: {
            variant: {
                default: cn(
                    'bg-primary active:bg-primary/90 shadow-sm shadow-black/5',
                    Platform.select({ web: 'hover:bg-primary/90' })
                ),
                destructive: cn(
                    'bg-destructive active:bg-destructive/90 dark:bg-destructive/60 shadow-sm shadow-black/5',
                    Platform.select({
                        web: 'hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40',
                    })
                ),
                outline: cn(
                    'border-border bg-background active:bg-accent dark:bg-input/30 dark:border-input dark:active:bg-input/50 border shadow-sm shadow-black/5',
                    Platform.select({
                        web: 'hover:bg-accent dark:hover:bg-input/50',
                    })
                ),
                secondary: cn(
                    'bg-secondary active:bg-secondary/80 shadow-sm shadow-black/5',
                    Platform.select({ web: 'hover:bg-secondary/80' })
                ),
                ghost: cn(
                    'active:bg-accent dark:active:bg-accent/50',
                    Platform.select({ web: 'hover:bg-accent dark:hover:bg-accent/50' })
                ),
                link: '',
            },
            size: {
                default: cn('h-10 px-4 py-2 sm:h-9', Platform.select({ web: 'has-[>svg]:px-3' })),
                sm: cn('h-9 gap-1.5 rounded-md px-3 sm:h-8', Platform.select({ web: 'has-[>svg]:px-2.5' })),
                lg: cn('h-11 rounded-md px-6 sm:h-10', Platform.select({ web: 'has-[>svg]:px-4' })),
                icon: 'h-10 w-10 sm:h-9 sm:w-9',
            },
        },
        defaultVariants: {
            variant: 'default',
            size: 'default',
        },
    }
);

const buttonTextVariants = cva(
    cn(
        'text-foreground text-sm font-medium',
        Platform.select({ web: 'pointer-events-none transition-colors' })
    ),
    {
        variants: {
            variant: {
                default: 'text-primary-foreground',
                destructive: 'text-white',
                outline: cn(
                    'group-active:text-accent-foreground',
                    Platform.select({ web: 'group-hover:text-accent-foreground' })
                ),
                secondary: 'text-secondary-foreground',
                ghost: 'group-active:text-accent-foreground',
                link: cn(
                    'text-primary group-active:underline',
                    Platform.select({ web: 'underline-offset-4 hover:underline group-hover:underline' })
                ),
            },
            size: {
                default: '',
                sm: '',
                lg: '',
                icon: '',
            },
        },
        defaultVariants: {
            variant: 'default',
            size: 'default',
        },
    }
);

type ButtonProps = React.ComponentProps<typeof Pressable> &
    React.RefAttributes<typeof Pressable> &
    VariantProps<typeof buttonVariants>;

function Button({ className, variant, size, ...props }: ButtonProps) {
    return (
        <TextClassContext.Provider value={buttonTextVariants({ variant, size })}>
            <Pressable
                className={cn(props.disabled && 'opacity-50', buttonVariants({ variant, size }), className)}
                role="button"
                {...props}
            />
        </TextClassContext.Provider>
    );
}

export { Button, buttonTextVariants, buttonVariants };
export type { ButtonProps };

import { cn } from '@/registry/lib/utils';
import * as Slot from '@rn-primitives/slot';
import { cva, type VariantProps } from 'class-variance-authority';
import * as React from 'react';
import { Platform, Text as RNText, type Role } from 'react-native';

const textVariants = cva(
    cn(
        'text-foreground text-base',
        Platform.select({
            web: 'select-text',
        })
    ),
    {
        variants: {
            variant: {
                default: '',
                h1: cn(
                    'text-center text-4xl font-extrabold tracking-tight',
                    Platform.select({ web: 'scroll-m-20 text-balance' })
                ),
                h2: cn(
                    'border-border border-b pb-2 text-3xl font-semibold tracking-tight',
                    Platform.select({ web: 'scroll-m-20 first:mt-0' })
                ),
                h3: cn('text-2xl font-semibold tracking-tight', Platform.select({ web: 'scroll-m-20' })),
                h4: cn('text-xl font-semibold tracking-tight', Platform.select({ web: 'scroll-m-20' })),
                p: 'mt-3 leading-7 sm:mt-6',
                blockquote: 'mt-4 border-l-2 pl-3 italic sm:mt-6 sm:pl-6',
                code: cn(
                    'bg-muted relative rounded px-[0.3rem] py-[0.2rem] font-mono text-sm font-semibold'
                ),
                lead: 'text-muted-foreground text-xl',
                large: 'text-lg font-semibold',
                small: 'text-sm font-medium leading-none',
                muted: 'text-muted-foreground text-sm',
            },
        },
        defaultVariants: {
            variant: 'default',
        },
    }
);

type TextVariantProps = VariantProps<typeof textVariants>;

type TextVariant = NonNullable<TextVariantProps['variant']>;

const ROLE: Partial<Record<TextVariant, Role>> = {
    h1: 'heading',
    h2: 'heading',
    h3: 'heading',
    h4: 'heading',
    blockquote: Platform.select({ web: 'blockquote' as Role }),
    code: Platform.select({ web: 'code' as Role }),
};

const ARIA_LEVEL: Partial<Record<TextVariant, string>> = {
    h1: '1',
    h2: '2',
    h3: '3',
    h4: '4',
};

const TextClassContext = React.createContext<string | undefined>(undefined);

function Text({
    className,
    asChild = false,
    variant = 'default',
    ...props
}: React.ComponentProps<typeof RNText> &
    TextVariantProps &
    React.RefAttributes<RNText> & {
        asChild?: boolean;
    }) {
    const textClass = React.useContext(TextClassContext);
    const Component = asChild ? Slot.Text : RNText;
    return (
        <Component
            className={cn(textVariants({ variant }), textClass, className)}
            role={variant ? ROLE[variant] : undefined}
            aria-level={variant ? ARIA_LEVEL[variant] : undefined}
            {...props}
        />
    );
}

export { Text, TextClassContext };

import { cn } from '@/registry/lib/utils';
import { cva, type VariantProps } from 'class-variance-authority';
import * as React from 'react';
import { Platform, TextInput, type TextInputProps } from 'react-native';

const inputVariants = cva(
    cn(
        'border-input bg-background text-foreground placeholder:text-muted-foreground h-10 w-full rounded-md border px-3 py-2 text-sm',
        Platform.select({
            web: 'flex focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50 transition-shadow',
        })
    ),
    {
        variants: {
            variant: {
                default: '',
                ghost: 'border-transparent bg-transparent shadow-none active:bg-accent/50',
            },
        },
        defaultVariants: {
            variant: 'default',
        },
    }
);

type InputProps = TextInputProps &
    VariantProps<typeof inputVariants> & {
        className?: string;
    };

function Input({ className, variant, ...props }: InputProps) {
    return (
        <TextInput
            className={cn(inputVariants({ variant }), props.editable === false && 'opacity-50', className)}
            placeholderTextColor="hsl(var(--muted-foreground))"
            {...props}
        />
    );
}

export { Input };
export type { InputProps };

import { TextClassContext } from '@/registry/components/ui/text';
import { cn } from '@/registry/lib/utils';
import { cva, type VariantProps } from 'class-variance-authority';
import * as React from 'react';
import { View, type ViewProps } from 'react-native';

const badgeVariants = cva(
    'inline-flex flex-row items-center rounded-full border px-2.5 py-0.5',
    {
        variants: {
            variant: {
                default: 'border-transparent bg-primary',
                secondary: 'border-transparent bg-secondary',
                destructive: 'border-transparent bg-destructive',
                outline: 'border-border',
            },
        },
        defaultVariants: {
            variant: 'default',
        },
    }
);

const badgeTextVariants = cva('text-xs font-semibold', {
    variants: {
        variant: {
            default: 'text-primary-foreground',
            secondary: 'text-secondary-foreground',
            destructive: 'text-white',
            outline: 'text-foreground',
        },
    },
    defaultVariants: {
        variant: 'default',
    },
});

type BadgeProps = ViewProps &
    VariantProps<typeof badgeVariants> & {
        className?: string;
    };

function Badge({ className, variant, children, ...props }: BadgeProps) {
    return (
        <TextClassContext.Provider value={badgeTextVariants({ variant })}>
            <View className={cn(badgeVariants({ variant }), className)} {...props}>
                {children}
            </View>
        </TextClassContext.Provider>
    );
}

export { Badge, badgeVariants };
export type { BadgeProps };

import { cn } from '@/registry/lib/utils';
import * as AvatarPrimitive from '@rn-primitives/avatar';
import * as React from 'react';

type AvatarProps = React.ComponentProps<typeof AvatarPrimitive.Root> & {
    className?: string;
};

function Avatar({ className, ...props }: AvatarProps) {
    return (
        <AvatarPrimitive.Root
            className={cn('relative h-10 w-10 shrink-0 overflow-hidden rounded-full', className)}
            {...props}
        />
    );
}

type AvatarImageProps = React.ComponentProps<typeof AvatarPrimitive.Image> & {
    className?: string;
};

function AvatarImage({ className, ...props }: AvatarImageProps) {
    return (
        <AvatarPrimitive.Image
            className={cn('aspect-square h-full w-full', className)}
            {...props}
        />
    );
}

type AvatarFallbackProps = React.ComponentProps<typeof AvatarPrimitive.Fallback> & {
    className?: string;
};

function AvatarFallback({ className, ...props }: AvatarFallbackProps) {
    return (
        <AvatarPrimitive.Fallback
            className={cn('bg-muted flex h-full w-full items-center justify-center rounded-full', className)}
            {...props}
        />
    );
}

export { Avatar, AvatarFallback, AvatarImage };
export type { AvatarFallbackProps, AvatarImageProps, AvatarProps };
